returnableFulfillments.query:
query ReturnableFulfillmentsRecorded($orderId: ID!) {
  returnableFulfillments(orderId: $orderId, first: 5) {
    nodes {
      fulfillment {
        id
      }
      returnableFulfillmentLineItems(first: 5) {
        nodes {
          fulfillmentLineItem {
            id
            lineItem {
              id
              title
            }
          }
          quantity
        }
      }
    }
  }
}

returnCalculate.query:
query ReturnCalculateRecorded($input: CalculateReturnInput!) {
  returnCalculate(input: $input) {
    returnLineItems {
      fulfillmentLineItem {
        id
        lineItem {
          id
          title
        }
      }
      quantity
      restockingFee {
        id
        percentage
        amountSet {
          shopMoney {
            amount
            currencyCode
          }
        }
      }
      subtotalBeforeOrderDiscountsSet {
        shopMoney {
          amount
          currencyCode
        }
      }
      subtotalSet {
        shopMoney {
          amount
          currencyCode
        }
      }
      totalTaxSet {
        shopMoney {
          amount
          currencyCode
        }
      }
    }
    returnShippingFee {
      id
      amountSet {
        shopMoney {
          amount
          currencyCode
        }
      }
    }
  }
}

orderCancel.query:
mutation ReturnQueryRootsOrderCancel(
    $orderId: ID!
    $reason: OrderCancelReason!
    $notifyCustomer: Boolean!
    $restock: Boolean!
  ) {
    orderCancel(orderId: $orderId, reason: $reason, notifyCustomer: $notifyCustomer, restock: $restock) {
      job {
        id
      }
      userErrors {
        field
        message
      }
    }
  }

orderDelete.query:
mutation ReturnQueryRootsOrderDelete($orderId: ID!) {
    orderDelete(orderId: $orderId) {
      deletedId
      userErrors {
        field
        message
      }
    }
  }

